var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"글쎄, 해줄 말이고 자시고 도망부터 가라고!","JPN":"だから、伝えたいことも何も、逃げるのが先だってば！","ENG":"There’s no time! Just go already!","TWN":"不用啦，沒什麼好說的，先逃吧！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"아까 그 여자.","JPN":"さっきのあの女。","ENG":"That woman...","TWN":"剛剛那個女的，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"……헤론 님?","JPN":"……ヘロン様？","ENG":"You mean Madam Heron?","TWN":"……海倫夫人？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"응. 위저드에 있던 아이들…… 그리고 글린다 네 꿈에 그 여자가 나왔어.","JPN":"うん。ウィザードにいた子どもたち……そしてグリンダ、あなたの夢にもあの女がいた。","ENG":"Yes. She’s the one who appears in your dreams... and the Wizard children’s.","TWN":"嗯，在魔法師的孩子們……和你的夢裡，那個女的都曾經出現過。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"내…… 꿈에?","JPN":"私の……夢に？","ENG":"In... my dreams?","TWN":"我的……夢裡？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"네 악몽에. 널 괴롭히던 악몽이 그 여자 모습이었어.","JPN":"あなたの悪夢に。グリンダを苦しめた悪夢があの女の姿だったの。","ENG":"In your nightmare. The thing that haunted you looked just like her.","TWN":"在你的惡夢裡，折磨你的惡魔就是她。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그럴 리가 없어…… 헤론 님은 항상 우리에게 다정하셨는데…….","JPN":"そんなはずない……ヘロン様はいつも私たちに優しくしてくださったんだ……","ENG":"There’s no way... But Madam Heron was so nice to us...","TWN":"怎麼可能……海倫夫人對我們都很親切……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"사람들은 자기가 누구에게 괴롭힘 당하는지 모를 수 있지.","JPN":"人は自分が誰のせいで苦しんでるのかわからないこともあるよ。","ENG":"People can’t usually tell who’s bullying them.","TWN":"人們有可能不清楚是誰在傷害自己，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"보통은 교묘하게 자신의 책임을 회피하며 남 탓으로 모든 걸 넘겨 버리니까.","JPN":"普通は巧みに自分の責任を回避して、すべて他人のせいにしちゃうから。","ENG":"That’s because bullies avoid any responsibility and just blame it on others.","TWN":"通常都是巧妙地避開自己的責任，把一切都推卸給別人。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"하지만…… 뇌는 바보가 아니야. 무의식은 알아. ","JPN":"でも……脳はバカじゃないの。無意識は知ってる。 ","ENG":"However... The brain isn’t stupid. Your subconscious knows.","TWN":"不過……大腦不是笨蛋，潛意識裡很清楚，"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"누가 나를 힘들게 하는지, 꿈은 솔직하게 보여줄 수 있어.","JPN":"誰が自分を苦しめてるのか、夢はありのままを見せてくれる。","ENG":"It knows who’s making you suffer, and reflects it in your dreams.","TWN":"在夢裡會真實地呈現出來，是誰在折磨我。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다. 난 그런 사람 옆에 널 두고 갈 수 없어.","JPN":"グリンダ。私はそんな人のそばにあなたを置いて行けないよ。","ENG":"Glinda. I'm not going to leave you with someone like that.","TWN":"格琳達，我不能把你丟給那種人自己逃掉。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루…….","JPN":"ルル……","ENG":"Lulu...","TWN":"露露……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"휴. 재미없어.","JPN":"ふう、つまらないわね。","ENG":"Ugh... This is unamusing.","TWN":"哀～真是無聊。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"재미없는 건 헤이븐 님 성미에 그냥 내버려둘 수 없지.","JPN":"ヘイブン様の性格上、つまらないものは放っておけないのよ。","ENG":"\\"Unentertaining\\" doesn’t suit Mr. Haven’s style.","TWN":"天堂先生可無法容忍無聊。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님의 명령이에요. 저 양털 같이 축 늘어진 아이는 데려가죠.","JPN":"ヘイブン様のご命令です。あの濡れた羊毛のようにぐったりしてる子を連れて行きなさい。","ENG":"Mr. Haven’s orders. Take that woolly girl away.","TWN":"這是天堂先生的命令，把那個頭上長羊角的孩子帶走。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MOB_HAVEN_NULL_B","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루루를 어디로 데려가려고요!","JPN":"ルルをどこに連れて行くんですか！","ENG":"Where are you taking Lulu?!","TWN":"你們要把露露帶去哪裡！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L27_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그야 당연하지 않겠니?","JPN":"それは決まってるでしょう？","ENG":"Isn’t it obvious?","TWN":"這不是很明顯嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님께서 이런 능력을 가진 아이를 그냥 두실 리가 없지.","JPN":"ヘイブン様がこんな能力を持った子をこのまま放っておくわけがないわ。","ENG":"There’s no way Mr. Haven would just leave a child with this kind of ability alone, would he?","TWN":"天堂先生怎麼可能放過有特殊能力的人？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그나마 내가 자비를 베풀어 스스로 할 수 있게끔 기회를 준 건데…… 걷어찬 건 너희다?","JPN":"私が慈悲を施して、自分で決められるようにチャンスをあげたのに……あなたたちが拒否したのよ？","ENG":"I was gracious enough to give you the opportunity to persuade her yourself. But you're the one who blew it.","TWN":"我已經大發善心給過你們機會……是你們自己放棄的？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"하지만……!","JPN":"でも……！","ENG":"But...!","TWN":"可是……！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L34_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"스스로 생각할 수 없도록 만드실 거야. 혼자서는 아무것도 못 하게.","JPN":"自分で考えられないようにされるはずよ。一人では何もできないように。","ENG":"He intends to turn her into a puppet. She won't be able to do anything on her own.","TWN":"天堂先生會把她弄到無法自行思考，也沒有行為能力。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"글린다 네 말처럼 능력만 뽑아내는 기계로 사용하실 생각이셔.","JPN":"グリンダ、あなたの言ったように、能力だけ利用できる機械として使うおつもりよ。","ENG":"Like you said, Glinda. She’ll be a nightmare-eating machine.","TWN":"格琳達，你說的沒錯，天堂先生只當她是機器，想要利用她的能力而已。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아! 몸도 성할 필요가 없겠다고 하셨었지. 살아만 있으면 될 테니까. 안 그러니?","JPN":"そうね！　体も無傷である必要はないとおっしゃったっけ。生きてさえいればいいのだから。ねえ？","ENG":"Oh! He also mentioned that she doesn’t need to be well kept. Just as long as she can do her job. Isn't that right?","TWN":"喔！他還說不需要四肢健全，只要會呼吸就好，對吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그런… 그런 잔인한 짓을 헤이븐 형님이 하실 리가 없어…….","JPN":"そんな……ヘイブン兄貴がそんな酷いことをするわけない……","ENG":"There’s... There’s no way Mr. Haven would be so cruel...","TWN":"什…天堂大哥才不會做出這麼殘忍的事……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L41_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"자비없고 냉정한 모습이 바로 헤이븐 님의 진면모지. 그 호쾌한 모습이 어쩔 땐 아름답게 느껴지기까지 한다니까?","JPN":"無慈悲で、冷淡な姿こそヘイブン様の真の姿なのよ。あの豪快な姿、時には美しくも見えるんだから。","ENG":"Mr. Haven’s true character is merciless and cold-hearted. Sometimes I see his true nature and can’t help but think of how beautiful it is...","TWN":"冷酷無情就是天堂先生的真面目，而且有時候還蠻賞心悅目的呢？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L42_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"미쳤어… 제정신이 아니야…….","JPN":"いかれてる……正気じゃない……","ENG":"You’re... You’re all crazy...","TWN":"神經病…你有毛病……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L44_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저런, 글린다. 그 예쁜 입술로 못된 말을 하다니. 정말 벌을 주지 않고는 못 배기게 만드는구나.","JPN":"あら、グリンダ。キレイな口でそんな酷いことを言うなんて。本当にお仕置きしたくなるわね。","ENG":"Oh, Glinda... How could you say such hurtful words? Now I have to reconsider punishing you.","TWN":"真是的，格琳達。怎麼可以口出惡言呢？不懲罰你，你就管不住你那張嘴嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_IDLE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤, 헤론 님. 죄송해요. 죄송해요. 벌은 다 받을게요!","JPN":"ヘ、ヘロン様。ごめんなさい。ごめんなさい。お仕置きなら全部受けます！","ENG":"I-I’m sorry, Madam Heron. I really am. I’ll take the punishment!","TWN":"海…海倫夫人，對不起，都怪我不好，我願意接受懲罰！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그러니까, 루루를 그렇게 만들지는 말아 주세요… 불쌍한 애란 말이에요. 제발…….","JPN":"だから、ルルをそんな風にしないでください……かわいそうな子なんです。どうか……","ENG":"But please... Leave Lulu out of this. She’s just an innocent child... Please...","TWN":"拜託不要把露露變成那樣…她是個可憐的孩子……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"세상에. 글린다. 내가 충고 하나만 해 줘도 될까?","JPN":"あらまあ。グリンダ。一つ忠告してもいいかしら？","ENG":"My, my, Glinda. Here’s some advice for you.","TWN":"我的天，格琳達，可以給你個忠告嗎？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그렇게 착해 빠진 마음을 가졌다간 이 험한 세상에서 살아남기가 어려워.","JPN":"優しすぎると、この険しい世界で生き残るのは大変よ。","ENG":"This cruel world is going to eat you alive if you keep that kindheartedness of yours.","TWN":"善良在這險惡的世界裡是活不下去的。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그리고 착각하지 마. 고작 몇 달 전에 본 애를 위해 대신 벌을 받을 정도니, 네가?","JPN":"あと、勘違いはよくないわ。たった何か月か前に出会った子のために、代わりにお仕置きを受けるですって？","ENG":"And don’t fool yourself. Are you really willing to suffer for this girl you only met a few months ago?","TWN":"還有，你不要搞錯，你跟她才認識幾個月而已，你就要替她受罰？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아까 전까지만 해도 혼자 도망치려다 붙잡힌 건 누굴까?","JPN":"さっきまで一人で逃げようとして捕まったのは、どこの誰なのかしら？","ENG":"Wasn't it you who abandoned her and tried to save yourself?","TWN":"是誰之前才自己逃跑的？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"그건… 그건 다시 돌아와서 구해주려고 했는데…… 정말로 다시 돌아오려고 했어요…….","JPN":"それは……それは、また戻ってきて助けようと……本当に戻ってこようと思ってました……","ENG":"Th-that’s... because I was going to come back and get her... I was going to come back...","TWN":"那是…我原本是想再回去救她的……我說的是真的……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"헤론 님. 제가 다시 설득해 볼 테니 루루를 그렇게 만들지 말아 주세요…….","JPN":"ヘロン様。私がもう一度説得してみますから、ルルをそんな風にしないでください……","ENG":"Madam Heron, I’ll try to convince her again. So please, don’t hurt her...","TWN":"海倫夫人，我會再試著說服露露，拜託不要把她變成那樣……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NEWCOMER_NPC_DREAM_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"거머리처럼 들러붙네, 자꾸.","JPN":"何度も何度も、ヒルみたいにくっつくのね。","ENG":"My, aren’t you a clingy one...","TWN":"還真是纏人！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"다들 뭐해요? 이런 건 헤이븐 님이 아시기 전에 빨리 빨리 처리하는 게 좋아요.","JPN":"皆さん、何してるんですか？　こんなことはヘイブン様の耳に入る前にさっさと片付けた方がいいのです。","ENG":"What are you just standing around for? Take care of this before Mr. Haven finds out.","TWN":"愣著做什麼？趁現在事情還沒傳到天堂先生耳裡，還不快處理好。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MOB_HAVEN_NULL_A","text":{"KOREA":"예! 마담!","JPN":"はい！　マダム！","ENG":"Yes, Madam!","TWN":"是！夫人！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MOB_HAVEN_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다!!","JPN":"グリンダ！！","ENG":"Glinda!!","TWN":"格琳達！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다! 다들 그만해!!","JPN":"グリンダ！　みんなやめて！！","ENG":"Glinda! STOP!!!","TWN":"格琳達！全都住手！！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"흐으… 아파…….","JPN":"うう……痛い……","ENG":"Ugh... It hurts...","TWN":"呃呃…好痛……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"글린다…….","JPN":"グリンダ……","ENG":"Glinda...","TWN":"格琳達……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"흐읍. 흐으…… 내 불꽃…… 불꽃이…….","JPN":"ううっ。うう……私の炎……炎が……","ENG":"Hmmp... Hnngh... My flames... Why is it...","TWN":"唔…唔…我的火球……火球……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저런. 카운터랬나?","JPN":"あら。カウンターだったかしら？","ENG":"Did you say you were a Counter?","TWN":"哇，聽說你是制裁者？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"어떤 카운터도 정신이 흐트러지면 제대로 능력을 쓰기 어렵지.","JPN":"どんなカウンターでも、精神が乱れると能力をちゃんと使えないのよね。","ENG":"Even a Counter will struggle to use their abilities if they lose focus.","TWN":"就算是制裁者，精神渙散時也無法好好發揮能力吧？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그 정도 대비는 당연히 해 두었단다. 조금 희한한 능력 생겼다고 반항하는 애가 너뿐만은 아니었거든.","JPN":"そのくらいはもちろん準備しておいたわ。ちょっと珍しい能力ができたからって抵抗する子は、あなただけじゃなかったもの。","ENG":"I’ve already made the necessary precautions. You’re not the only one with strange powers who tried to rebel against us.","TWN":"你以為我們會毫無準備嗎？仗著有特殊能力就反抗的孩子可不止你一個呢。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"NIGHTMARE_DREAM_NULL_NULL","text":{"KOREA":"흐읍! 흐으읍……!","JPN":"ふうっ！　うううっ……！","ENG":"Hmph! Hmmph...!","TWN":"唔！唔唔……！"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"NIGHTMARE_DREAM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"소용없대도. 괜히 힘 빼지 말고 얌전히 차례를 기다리렴. 그렇게 발버둥치면 피가 더 빠질 거야.","JPN":"意味のないことを。無駄に力を使わないで、大人しくあなたの順番をお待ちなさい。そうやってジタバタしてると、出血がもっと酷くなるわ。","ENG":"It’s no use. Stop wasting energy and wait for your turn. All that wriggling is only going to make you bleed out faster.","TWN":"沒用的，我勸你別浪費力氣，等等就輪到你。再掙扎只會流更多血。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"더 다치지 않게 잘 데려가 줘요.","JPN":"これ以上怪我しないように、気をつけて連れて行ってくださいね。","ENG":"Take her away and don’t hurt her anymore.","TWN":"再傷得更重之前，乖乖跟我們走吧。"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"루… 루…… 미안…….","JPN":"ル……ル……ごめん……","ENG":"Lu... lu... I’m sorry...","TWN":"露…露……對不起……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"내가 할 수 있는 게…… 아무것도 없어…….","JPN":"私にできることって……何もない……","ENG":"There’s nothing... I can do...","TWN":"我什麼……都做不到……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"NEWCOMER_NPC_DREAM_NULL","text":{"KOREA":"나 같은 건…….","JPN":"私なんて……","ENG":"I’m...","TWN":"我真沒……"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"……지진?","JPN":"……地震？","ENG":"...An earthquake?","TWN":"……地震？"},"stage":{"bg":"PRISON_NIGHT_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}}]`);export{e as default};